mapper.select:
select a.*
from assignment a
join course c on c.id = a.course_id
where a.id = #{id}
  and a.status = 1
  and a.course_id = #{courseId}
  and c.teacher_id = #{teacherId}
  and c.status = 1
limit 1

select * from assignment_submission
where assignment_id = #{assignmentId} and student_id = #{studentId}
limit 1
